configuration.styles:

nav { background-color: #ebebeb !important; }
.report-name {
    padding-left: 40%;
    color: black;
    font-weight: bold;
}
.test-desc { font-size: 18px; }
.test-name { width: fit-content; }
.cyan { display: none; }
.orange { display: none; }
.darken-4 { display: none; }
.logo-content { display: none; }
.logo-container {
    background-color: #ebebeb !important;
    width: 46px;
}
.blue.darken-2 { background-color: #1A231E !important; }
.button-collapse { width: 50px; }
.side-nav { width: 50px; }
.analysis i { font-size: 15px !important; }
.side-nav.fixed a {
    padding: 18px;
    padding-top: 0px;
}
.step-details { word-break: inherit; }
._addedCell1 {
    min-width: 25%;
    max-width: 50%;
    width: 150px;
}
.step-filters { padding-bottom: 5px; }
.theme-selector,
.suite-started-time {
    color: black;
    font-weight: bold;
}
